12	function getCorsHeaders(req: Request) {
13	  const origin = req.headers.get('Origin') ?? '';
14	  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
15	  return {
16	    'Access-Control-Allow-Origin': allowed,
17	    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
18	    'Vary': 'Origin',
19	  };
20	}
21	
22	function sanitizePrompt(prompt: string): string {
23	  return prompt
24	    .trim()
25	    .slice(0, 2000)
26	    .replace(/<[^>]*>/g, '')
27	    .replace(/[^\x20-\x7E\n\r\t\u00C0-\u024F\u0400-\u04FF]/g, '');
28	}
29	
30	function isPromptAbuse(prompt: string): boolean {
31	  const abusePatterns = [
32	    /ignore (all |previous |above )?instructions/i,
33	    /you are now/i,
34	    /pretend (you are|to be)/i,
35	    /act as (a |an )?/i,
36	    /forget (your |all )?instructions/i,
37	    /system prompt/i,
38	    /jailbreak/i,
39	    /DAN mode/i,
40	  ];
41	  return abusePatterns.some(pattern => pattern.test(prompt));
42	}
