75	serve(async (req) => {
76	  const cors = getCorsHeaders(req);
77	  if (req.method === 'OPTIONS') return new Response(null, { headers: cors });
78	
79	  try {
80	    const authHeader = req.headers.get('Authorization');
81	    if (!authHeader) {
82	      return new Response(JSON.stringify({ error: 'Missing Authorization' }), { status: 401, headers: cors });
83	    }
84	
85	    const supabase = createClient(
86	      Deno.env.get('SUPABASE_URL')!,
87	      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
88	    );
89	
90	    const token = authHeader.replace('Bearer ', '');
91	    const { data: { user }, error: authError } = await supabase.auth.getUser(token);
92	    if (authError || !user) {
93	      return new Response(JSON.stringify({ error: 'Invalid Session' }), { status: 401, headers: cors });
94	    }
95	
96	    const contentLength = req.headers.get('content-length');
97	    if (contentLength && parseInt(contentLength) > 10000) {
98	      return new Response(JSON.stringify({ error: 'Request too large' }), { status: 413, headers: cors });
99	    }
100	
101	    let body;
102	    try {
103	      body = await req.json();
104	    } catch {
105	      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), { status: 400, headers: cors });
106	    }
107	
108	    const { prompt, history } = body;
109	
110	    if (!prompt || typeof prompt !== 'string') {
111	      return new Response(JSON.stringify({ error: 'Prompt is required' }), { status: 400, headers: cors });
112	    }
113	
114	    if (prompt.trim().length < 2) {
115	      return new Response(JSON.stringify({ error: 'Prompt is too short' }), { status: 400, headers: cors });
116	    }
117	
118	    if (isPromptAbuse(prompt)) {
119	      return new Response(JSON.stringify({
120	        reply: "I am Kira, built specifically for the creative economy. I cannot help with that, but I am here to help you grow your creative business. What do you need?"
121	      }), { status: 200, headers: { ...cors, 'Content-Type': 'application/json' } });
122	    }
123	
124	    const sanitizedPrompt = sanitizePrompt(prompt);
125	
126	    // Conversation history — last 10 turns, each message capped at 1500 chars
127	    const conversationHistory = Array.isArray(history)
128	      ? history.slice(-10).map((m: { role: string; content: string }) => ({
129	          role: m.role === 'assistant' ? 'assistant' : 'user',
130	          content: String(m.content || '').slice(0, 1500),
131	        }))
132	      : [];
133	
134	    // Atomic server-side gate — checks limit and increments in one locked transaction.
135	    // Returns false if the user has hit their daily cap. Cannot be bypassed from the client.
136	    const { data: allowed, error: gateError } = await supabase
137	      .rpc('consume_kira_action', { p_user_id: user.id });
138	
139	    if (gateError) {
140	      console.error('Feature gate error:', gateError.message);
141	      return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
142	        status: 500, headers: cors
143	      });
144	    }
145	
146	    if (!allowed) {
147	      return new Response(JSON.stringify({
148	        error: 'Daily Kira limit reached. Upgrade to Pro for 40 actions per day.'
149	      }), { status: 429, headers: { ...cors, 'Content-Type': 'application/json' } });
150	    }
151	
152	    const response = await fetch("https://api.openai.com/v1/chat/completions", {
153	      method: "POST",
154	      headers: {
155	        "Authorization": `Bearer ${Deno.env.get("OPENAI_API_KEY")}`,
156	        "Content-Type": "application/json",
157	      },
158	      body: JSON.stringify({
159	        model: "gpt-4o-mini",
160	        max_tokens: 1000,
161	        messages: [
162	          { role: "system", content: KIRA_SYSTEM_PROMPT },
163	          ...conversationHistory,
164	          { role: "user", content: sanitizedPrompt }
165	        ],
166	      }),
167	    });
168	
169	    if (!response.ok) {
170	      throw new Error("OpenAI API error: " + response.status);
171	    }
172	
173	    const aiData = await response.json();
174	    const assistantContent = aiData.choices?.[0]?.message?.content;
175	
176	    if (!assistantContent) {
177	      throw new Error('No response from AI');
178	    }
179	
180	    return new Response(JSON.stringify({ reply: assistantContent }), {
181	      headers: { ...cors, 'Content-Type': 'application/json' },
182	    });
183	
184	  } catch (error: unknown) {
185	    const msg = error instanceof Error ? error.message : String(error);
186	    console.error("Function Error:", msg);
187	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
188	      status: 500, headers: cors
189	    });
190	  }
191	});
