1	import { serve } from "https://deno.land/std@0.208.0/http/server.ts";
2	import { createClient } from "https://esm.sh/@supabase/supabase-js@2.47.0";
3	
4	const supabaseUrl = Deno.env.get("SUPABASE_URL") || "";
5	const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") || "";
6	
7	serve(async (req) => {
8	  // Verify this is called from Supabase Cron or an authorized source
9	  const authHeader = req.headers.get("authorization");
10	  const cronSecret = Deno.env.get("CRON_SECRET");
11	  if (authHeader !== `Bearer ${Deno.env.get("CRON_SECRET")}`) {
12	    return new Response(
13	      JSON.stringify({ error: "Unauthorized: Secret mismatch" }),
14	      { status: 401, headers: { "Content-Type": "application/json" } }
15	    );
16	  }
17	
18	  const supabase = createClient(supabaseUrl, supabaseServiceKey);
19	
20	  try {
21	    // Reset all users' daily token counters and update last_reset timestamp
22	    //added select() so that i can how many users were reset
23	    const { data, error } = await supabase
24	      .from("profiles")
25	      .update({
26	        kira_tokens_used_today: 0,
27	        kira_last_reset: new Date().toISOString(),
28	      })
29	    //   .neq("id", ""); // Update all rows
30	    .not("id", "is", null) // a more reliable way to select rows in Supabase
31	    .select(); // Return the updated rows
32	
33	    if (error) throw error;
34	
35	    return new Response(
36	      JSON.stringify({
37	        success: true,
38	        message: `Reset tokens for ${data?.length || 0} users`,
39	      }),
40	      { status: 200, headers: { "Content-Type": "application/json" } }
41	    );
42	  } catch (error) {
43	    return new Response(
44	      JSON.stringify({ error: error.message }),
45	      { status: 500, headers: { "Content-Type": "application/json" } }
46	    );
47	  }
48	});

