82	const Kira = () => {
83	  const { toast } = useToast();
84	  const { kiraActionsToday, kiraActionsLimit } = useSubscription();
85	  const [userType, setUserType] = useState<'creator' | 'brand' | null>(null);
86	  const [userId, setUserId] = useState<string | null>(null);
87	  const [isLoading, setIsLoading] = useState(false);
88	  const [isLoadingHistory, setIsLoadingHistory] = useState(true);
89	  const messagesEndRef = useRef<HTMLDivElement>(null);
90	
91	  useEffect(() => {
92	    window.scrollTo(0, 0);
93	  }, []);
94	
95	  const creatorGreetings = [
96	    "Hey there! Let's build something great today",
97	    "The world needs your story — let's tell it better",
98	    "Ready to turn creative vision into action?",
99	    "Your next big collaboration starts here",
100	    "Let's craft content that truly resonates"
101	  ];
102	
103	  const brandGreetings = [
104	    "Hey there! Let's find the perfect storytellers for your brand",
105	    "Ready to connect with creators who share your vision?",
106	    "Your next winning campaign starts here",
107	    "Let's build partnerships that drive real impact",
108	    "Time to create something your audience will love"
109	  ];
110	
111	  const greetings = userType === 'brand' ? brandGreetings : creatorGreetings;
112	
113	  const getGreeting = () => {
114	    const lastChange = localStorage.getItem('kira-greeting-date');
115	    const storedIndex = localStorage.getItem('kira-greeting-index');
116	    const today = new Date().toDateString();
117	    
118	    if (lastChange !== today) {
119	      const currentIndex = storedIndex ? parseInt(storedIndex) : 0;
120	      const newIndex = (currentIndex + 1) % greetings.length;
121	      localStorage.setItem('kira-greeting-date', today);
122	      localStorage.setItem('kira-greeting-index', newIndex.toString());
123	      return greetings[newIndex];
124	    }
